DVPMAN ;DAL/BNT - Digital Veterans Platform FHIR Functions;5/19/2017
 ;;1.0;DIGITAL VETERANS PLATFORM;****;
 ;
 ;Per VA Directive 6402, this routine should not be modified.
 ;
GETVER(SOURCE,TARGET) ;
 S @TARGET@("results","dvpVersion")=$P($T(VERSION+1^DVPVER),";",3)
 Q
 ;
GETDBVER(SOURCE,TARGET) ;
 S @TARGET@("results","dbVersion")=$G(^DVP("VERSION","MAJOR"))_"."_$G(^DVP("VERSION","MINOR"))_"."_$G(^DVP("VERSION","RELEASE"))
 Q
